import { setup, assign } from 'xstate';

type Ctx = { count: number; min: number; max: number };
type Ev =
  | { type: 'INC' }
  | { type: 'DEC' }
  | { type: 'RESET' }
  | { type: 'SET_BOUNDS'; min: number; max: number };

const clamp = (n: number, min: number, max: number): number =>
  Math.min(max, Math.max(min, n));

export const boundedCounter = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
  },
}).createMachine({
  id: 'bounded',
  context: { count: 0, min: 0, max: 10 },
  on: {
    INC: {
      actions: assign({
        count: ({ context }) => clamp(context.count + 1, context.min, context.max),
      }),
    },
    DEC: {
      actions: assign({
        count: ({ context }) => clamp(context.count - 1, context.min, context.max),
      }),
    },
    RESET: {
      actions: assign({ count: ({ context }) => context.min }),
    },
    SET_BOUNDS: {
      actions: assign({
        min: ({ event }) => event.min,
        max: ({ event }) => event.max,
        count: ({ context, event }) => clamp(context.count, event.min, event.max),
      }),
    },
  },
});
